318	// ApplyLandingToResult merges a BeadLandingResult's fields into an
319	// ExecuteBeadResult so callers can output a single unified record. It
320	// overwrites Outcome, Status, Detail, Reason, PreserveRef, GateResults,
321	// RequiredExecSummary, and ChecksFile based on the landing decision.
322	func ApplyLandingToResult(res *ExecuteBeadResult, landing *BeadLandingResult) {
323		res.Outcome = landing.Outcome
324		res.Reason = landing.Reason
325		res.PreserveRef = landing.PreserveRef
326		res.GateResults = landing.GateResults
327		res.RequiredExecSummary = landing.RequiredExecSummary
328		res.ChecksFile = landing.ChecksFile
329		res.RatchetEvidence = landing.RatchetEvidence
330		res.RatchetSummary = landing.RatchetSummary
331		// Re-classify status based on landing outcome and reason.
332		res.Status = ClassifyExecuteBeadStatus(landing.Outcome, res.ExitCode, landing.Reason)
333		res.Detail = ExecuteBeadStatusDetail(res.Status, landing.Reason, res.Error)
334		// Refine failure_mode with landing-level signals. A clean merge clears
335		// the field; merge conflict or gate failure overrides the worker-level
336		// classification; other preserved outcomes keep the worker's mode.
337		res.FailureMode = classifyLandingFailureMode(landing.Outcome, landing.Reason, landing.GateResults, res.FailureMode)
