340	// ExtractGoverningIDsFromManifest reads governing artifact IDs from a manifest
341	// JSON file at manifestAbs (absolute path). Returns nil when the file cannot
342	// be read. Callers use this to populate BeadLandingOptions.GovernIDs.
343	func ExtractGoverningIDsFromManifest(manifestAbs string) []string {
344		if manifestAbs == "" {
345			return nil
346		}
347		type manifestShape struct {
348			Governing []struct {
349				ID string `json:"id"`
350			} `json:"governing"`
351		}
352		raw, err := os.ReadFile(manifestAbs)
353		if err != nil {
354			return nil
355		}
356		var m manifestShape
357		if err := json.Unmarshal(raw, &m); err != nil {
358			return nil
359		}
360		ids := make([]string, 0, len(m.Governing))
361		for _, g := range m.Governing {
362			if g.ID != "" {
363				ids = append(ids, g.ID)
364			}
365		}
366		return ids
367	}
