721	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
722	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
723	// DDx-authored beads always round-trip through `bd import`. Empirically
724	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
725	const MaxFieldBytes = 65535
726	
727	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
728	// need to preserve the full payload should persist it to a sidecar artifact
729	// and store a path reference in the field; this function is the defense-in-
730	// depth cap for code paths that don't. Returns the input unchanged when it
731	// fits; otherwise returns head+tail truncation with a byte-count marker.
732	func capFieldBytes(s string) string {
733		if len(s) <= MaxFieldBytes {
734			return s
735		}
736		// Reserve a marker that always fits; keep head heavy (2/3) so
737		// human-readable context is preserved for the common short-rationale case.
738		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
739		budget := MaxFieldBytes - len(marker)
740		if budget <= 0 {
741			return s[:MaxFieldBytes]
742		}
743		head := (budget * 2) / 3
744		tail := budget - head
745		return s[:head] + marker + s[len(s)-tail:]
746	}
