607	// an error if the bead is no longer in_progress (e.g., reclaimed by another
608	// worker), allowing the caller to stop its heartbeat loop.
609	func (s *Store) Heartbeat(id string) error {
610		return s.WithLock(func() error {
611			beads, _, err := s.readAllLatestRaw()
612			if err != nil {
613				return err
614			}
615			for i := range beads {
616				if beads[i].ID != id {
617					continue
618				}
619				if beads[i].Status != StatusInProgress {
620					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, beads[i].Status)
