622				if beads[i].Extra == nil {
623					beads[i].Extra = make(map[string]any)
624				}
625				beads[i].Extra["execute-loop-heartbeat-at"] = time.Now().UTC().Format(time.RFC3339Nano)
626				beads[i].UpdatedAt = time.Now().UTC()
627				return s.WriteAll(beads)
628			}
629			return fmt.Errorf("bead: not found: %s", id)
630		})
631	}
